/// Simple observer that logs events via `tracing`.
pub struct LoggingObserver;

#[async_trait]
impl TuningEventObserver for LoggingObserver {
    #[instrument(skip_all)]
    async fn on_trial_start(&self, trial_id: usize, params: &HyperParams) {
        debug!(trial_id, params = %serde_json::to_string(params).unwrap_or_default(), "trial started");
    }

    #[instrument(skip_all)]
    async fn on_trial_complete(
        &self,
        trial_id: usize,
        params: &HyperParams,
        metric: &Result<Metric, TuningError>,
    ) {
        match metric {
            Ok(m) => info!(trial_id, metric_value = m.value, "trial completed"),
            Err(e) => warn!(trial_id, error = %e, "trial failed"),
        }
    }

    #[instrument(skip_all)]
    async fn on_tuning_complete(&self, result: &Result<TuningResult, TuningError>) {
        match result {
            Ok(res) => info!(
                best_value = res.best_metric.value,
                best_params = %serde_json::to_string(&res.best_params).unwrap_or_default(),
                "tuning finished"
            ),
            Err(e) => error!(error = %e, "tuning failed"),
        }
    }
}

/// Attach an observer to the bus; returns a detach-able async task.
pub fn attach_observer<O: TuningEventObserver + 'static>(
    bus: &TuningEventBus,
    observer: Arc<O>,
) -> tokio::task::JoinHandle<()> {
    let mut rx = bus.subscribe();
    tokio::spawn(async move {
        while let Ok(event) = rx.recv().await {
            match event {
                TuningEvent::TrialStart { trial_id, params } => {
                    observer.on_trial_start(trial_id, &params).await;
                }
                TuningEvent::TrialComplete {
                    trial_id,
                    params,
                    metric,
                } => {
                    observer
                        .on_trial_complete(trial_id, &params, &metric)
                        .await;
                }
                TuningEvent::TuningComplete { result } => {
                    observer.on_tuning_complete(&result).await;
                }
            }
        }
    })
}

/// Log hyperparameters using the ExperimentTracker trait abstraction.
///
/// This function demonstrates the decoupled experiment tracking pattern.
/// It accepts any type that implements `ExperimentTracker`, allowing for
/// easy testing with mocks and swapping of tracking backends.
pub fn log_hyperparameters_to_tracker<T: ExperimentTracker>(
    tracker: &T,
    params: &HyperParams,
) {
    for (name, value) in params {
        tracker.log_hyperparameter(name, &value.to_string());
    }
}

/// Log tuning metrics using the ExperimentTracker trait abstraction.
///
/// Records the metric value at the specified step using the provided tracker.
pub fn log_tuning_metric<T: ExperimentTracker>(
    tracker: &T,
    metric: &Metric,
    step: u64,
) {
    tracker.log_scalar(&metric.name, metric.value, step);
}

/// Run a complete tuning session with experiment tracking.
///
/// This function integrates the tuning process with experiment tracking,
/// logging all hyperparameters and metrics through the provided tracker.
pub async fn run_tuning_with_tracking<T: ExperimentTracker, M: ModelTrainer + 'static>(
    tracker: &T,
    trainer: Arc<M>,
    search_space: Vec<HyperParams>,
) -> Result<TuningResult, TuningError> {
    let tuner = GridSearchTuner::new(trainer, search_space, 16, None);

    // Subscribe to events and log them to the tracker
    let bus = tuner.event_bus();
    let tracker_step = std::sync::atomic::AtomicU64::new(0);

    let result = tuner.tune().await;

    // Log the best result
    if let Ok(ref res) = result {
        log_hyperparameters_to_tracker(tracker, &res.best_params);
        log_tuning_metric(tracker, &res.best_metric, tracker_step.load(std::sync::atomic::Ordering::Relaxed));
    }

    result
}

