    #[tokio::test]
    async fn model_registry_versioning() {
        let registry = ModelRegistry::default();

        let v1 = registry.register(
            &"test".into(),
            HashMap::from([("lr".into(), 0.01)]),
            HashMap::from([("acc".into(), 0.9)]),
        ).unwrap();

        let v2 = registry.register(
            &"test".into(),
            HashMap::from([("lr".into(), 0.001)]),
            HashMap::from([("acc".into(), 0.95)]),
