    42→/// Maximum number of historical events kept in memory per model.
    43→const MAX_WINDOW_SIZE: usize = 5_000;
    44→/// Channel size for metric ingestion.
    45→const METRIC_CHANNEL_CAPACITY: usize = 2048;
    46→/// Channel size for retraining job queue.
    47→const RETRAIN_CHANNEL_CAPACITY: usize = 128;
    48→/// Default evaluation interval (how often we evaluate retraining strategies).
    49→const DEFAULT_EVALUATION_INTERVAL: Duration = Duration::from_secs(60);
