    51→/// Error types specific to Monitoring.
    52→#[derive(Debug, Error)]
    53→pub enum MonitorError {
    54→    #[error("metrics channel closed")]
    55→    ChannelClosed,
    56→    #[error("failed to send retraining job: {0}")]
