    94→/// Metric payload emitted by serving-layer components.
    95→#[derive(Debug, Clone, Serialize, Deserialize)]
    96→pub struct MetricEvent {
    97→    pub model_id: String,
    98→    /// Unix-timestamp in milliseconds.
    99→    pub ts: u128,
   100→    /// End-to-end request latency observed by the client (ms).
   101→    pub latency_ms: f64,
   102→    /// Instantaneous throughput (# predictions / sec)
   103→    pub throughput: f64,
   104→    /// Running accuracy estimate (0.0 – 1.0) if labels available.
   105→    pub accuracy: Option<f64>,
   106→}
   107→
   108→impl MetricEvent {
   109→    pub fn now(
   110→        model_id: impl Into<String>,
   111→        latency_ms: f64,
   112→        throughput: f64,
   113→        accuracy: Option<f64>,
   114→    ) -> Self {
   115→        Self {
   116→            model_id: model_id.into(),
   117→            ts: SystemTime::now()
   118→                .duration_since(SystemTime::UNIX_EPOCH)
   119→                .expect("time went backwards")
   120→                .as_millis(),
   121→            latency_ms,
   122→            throughput,
   123→            accuracy,
   124→        }
   125→    }
   126→}
   127→
   128→/// Rolling collection of metric events for a single model.
   129→#[derive(Debug, Default)]
   130→struct MetricWindow {
   131→    /// Time-ordered ring-buffer
   132→    events: VecDeque<MetricEvent>,
   133→    /// Pre-aggregated stats for constant-time observers
   134→    latency_sum: f64,
   135→    throughput_sum: f64,
   136→    accuracy_sum: f64,
   137→    accuracy_cnt: usize,
   138→}
   139→
   140→impl MetricWindow {
   141→    fn push(&mut self, evt: MetricEvent) {
   142→        if self.events.len() == MAX_WINDOW_SIZE {
   143→            if let Some(old) = self.events.pop_front() {
   144→                self.latency_sum -= old.latency_ms;
   145→                self.throughput_sum -= old.throughput;
   146→                if let Some(acc) = old.accuracy {
   147→                    self.accuracy_sum -= acc;
   148→                    self.accuracy_cnt -= 1;
   149→                }
   150→            }
   151→        }
   152→
   153→        self.latency_sum += evt.latency_ms;
   154→        self.throughput_sum += evt.throughput;
   155→        if let Some(acc) = evt.accuracy {
   156→            self.accuracy_sum += acc;
   157→            self.accuracy_cnt += 1;
   158→        }
   159→
   160→        self.events.push_back(evt);
   161→    }
   162→
   163→    fn len(&self) -> usize {
   164→        self.events.len()
   165→    }
   166→
   167→    fn mean_latency(&self) -> f64 {
   168→        if self.events.is_empty() {
   169→            return 0.0;
   170→        }
   171→        self.latency_sum / self.events.len() as f64
   172→    }
   173→
   174→    fn mean_throughput(&self) -> f64 {
   175→        if self.events.is_empty() {
   176→            return 0.0;
   177→        }
   178→        self.throughput_sum / self.events.len() as f64
   179→    }
   180→
   181→    fn mean_accuracy(&self) -> Option<f64> {
   182→        if self.accuracy_cnt == 0 {
   183→            None
   184→        } else {
   185→            Some(self.accuracy_sum / self.accuracy_cnt as f64)
   186→        }
   187→    }
   188→
   189→    fn p99_latency(&self) -> f64 {
   190→        // naive percentile calc (production code may use histogram)
   191→        if self.events.is_empty() {
   192→            return 0.0;
   193→        }
   194→        let mut latencies: Vec<_> = self.events.iter().map(|e| e.latency_ms).collect();
   195→        latencies.sort_by(|a, b| a.partial_cmp(b).unwrap());
   196→        let idx = ((latencies.len() as f64) * 0.99).ceil() as usize - 1;
   197→        latencies[idx]
   198→    }
   199→}
