   201→/// What action an Observer suggests.
   202→#[derive(Debug, Clone, Copy, PartialEq)]
   203→enum MonitorAction {
   204→    Noop,
   205→    FlagRetrain,
   206→}
   207→
   208→/// Observer Pattern: notified of each model’s aggregated metrics.
   209→trait MetricObserver: Send + Sync {
   210→    /// Name (for logging/metrics)
   211→    fn name(&self) -> &'static str;
   212→    /// Evaluate window; return action.
   213→    fn on_update(&self, model: &str, window: &MetricWindow) -> MonitorAction;
   214→}
