   216→/// Observer that triggers retraining when P99 latency > threshold.
   217→struct LatencySlaObserver {
   218→    /// milliseconds
   219→    threshold_ms: f64,
   220→}
   221→
   222→impl LatencySlaObserver {
   223→    fn new(threshold_ms: f64) -> Self {
   224→        Self { threshold_ms }
   225→    }
   226→}
   227→
   228→impl MetricObserver for LatencySlaObserver {
   229→    fn name(&self) -> &'static str {
   230→        "latency_sla"
   231→    }
   232→
   233→    fn on_update(&self, model: &str, window: &MetricWindow) -> MonitorAction {
   234→        let p99 = window.p99_latency();
   235→        gauge!("model.p99_latency", p99, "model" => model);
   236→        if p99 > self.threshold_ms {
   237→            warn!(
   238→                "Model {} P99 latency {:.2}ms above threshold {:.2}ms",
   239→                model, p99, self.threshold_ms
   240→            );
   241→            return MonitorAction::FlagRetrain;
   242→        }
   243→        MonitorAction::Noop
   244→    }
   245→}
