   247→/// Observer that detects accuracy drift below threshold.
   248→struct AccuracyDriftObserver {
   249→    min_accuracy: f64,
   250→}
   251→
   252→impl AccuracyDriftObserver {
   253→    fn new(min_accuracy: f64) -> Self {
   254→        Self { min_accuracy }
   255→    }
   256→}
   257→
   258→impl MetricObserver for AccuracyDriftObserver {
   259→    fn name(&self) -> &'static str {
   260→        "accuracy_drift"
   261→    }
   262→
   263→    fn on_update(&self, model: &str, window: &MetricWindow) -> MonitorAction {
   264→        if let Some(acc) = window.mean_accuracy() {
   265→            gauge!("model.accuracy", acc, "model" => model);
   266→            if acc < self.min_accuracy {
   267→                warn!(
   268→                    "Model {} accuracy {:.4} below threshold {:.4}",
   269→                    model, acc, self.min_accuracy
   270→                );
   271→                return MonitorAction::FlagRetrain;
   272→            }
   273→        }
   274→        MonitorAction::Noop
   275→    }
   276→}
