   285→
   286→/// Strategy Pattern: decides—based on aggregated Observer signals—if we should
   287→/// create a RetrainJob.
   288→#[async_trait::async_trait]
   289→trait RetrainStrategy: Send + Sync {
   290→    /// Called periodically with aggregated observer actions
   291→    async fn evaluate(
   292→        &self,
   293→        model: &str,
   294→        actions: &[MonitorAction],
   295→        window: &MetricWindow,
   296→    ) -> Option<RetrainJob>;
   297→}
   298→
   299→/// Simple majority-vote strategy: if any FlagRetrain action is present,
   300→/// we create a job. Implements a debounce window to avoid spamming.
   301→struct MajorityStrategy {
   302→    /// minimum time between two jobs for the same model
   303→    cooldown: Duration,
   304→    /// book-keeping of last job timestamps
   305→    last_job_ts: Arc<RwLock<dashmap::DashMap<String, u128>>>,
   306→}
   307→
   308→impl MajorityStrategy {
   309→    fn new(cooldown: Duration) -> Self {
   310→        Self {
   311→            cooldown,
   312→            last_job_ts: Arc::new(RwLock::new(dashmap::DashMap::new())),
   313→        }
   314→    }
   315→}
   316→
   317→#[async_trait::async_trait]
   318→impl RetrainStrategy for MajorityStrategy {
   319→    async fn evaluate(
   320→        &self,
   321→        model: &str,
   322→        actions: &[MonitorAction],
   323→        _window: &MetricWindow,
   324→    ) -> Option<RetrainJob> {
   325→        if !actions.iter().any(|a| *a == MonitorAction::FlagRetrain) {
   326→            return None;
   327→        }
   328→
   329→        let now = SystemTime::now()
   330→            .duration_since(SystemTime::UNIX_EPOCH)
   331→            .unwrap()
   332→            .as_millis();
   333→
   334→        {
   335→            let m = self.last_job_ts.read().await;
   336→            if let Some(entry) = m.get(model) {
   337→                let last = *entry;
   338→                if now - last < self.cooldown.as_millis() {
   339→                    debug!("Skipping retrain for {model} due to cooldown");
   340→                    return None;
   341→                }
   342→            }
   343→        }
   344→
   345→        {
   346→            let mut m = self.last_job_ts.write().await;
   347→            m.insert(model.to_string(), now);
   348→        }
   349→
   350→        Some(RetrainJob {
   351→            model_id: model.to_string(),
   352→            reason: "observer_trigger".into(),
   353→            requested_at: now,
   354→        })
   355→    }
   356→}
