   358→/// Central engine wiring together observers + strategy.
   359→pub struct MonitorEngine {
   360→    metric_sink: MetricSink,
   361→    retrain_job_stream: RetrainJobStream,
   362→    /// keep JoinHandles for graceful shutdown
   363→    tasks: Vec<JoinHandle<()>>,
   364→}
   365→
   366→impl MonitorEngine {
   367→    pub fn start(
   368→        observers: Vec<Box<dyn MetricObserver>>,
   369→        strategy: Arc<dyn RetrainStrategy>,
   370→    ) -> Self {
   371→        let (metric_tx, mut metric_rx) = mpsc::channel::<MetricEvent>(METRIC_CHANNEL_CAPACITY);
   372→        let (retrain_tx, _) = broadcast::channel::<RetrainJob>(RETRAIN_CHANNEL_CAPACITY);
   373→
   374→        // In-memory state: per-model rolling window
   375→        let windows = Arc::new(RwLock::new(dashmap::DashMap::<String, MetricWindow>::new()));
   376→
   377→        // Task 1: metric ingestion
   378→        let windows_clone = Arc::clone(&windows);
   379→        let metric_task = tokio::spawn(async move {
   380→            while let Some(evt) = metric_rx.recv().await {
   381→                counter!("metric_events_ingested", 1, "model" => &evt.model_id);
   382→
   383→                let mut windows = windows_clone.write().await;
   384→                let window = windows
   385→                    .entry(evt.model_id.clone())
   386→                    .or_insert_with(MetricWindow::default);
   387→                window.push(evt);
   388→            }
   389→        });
   390→
   391→        // Task 2: periodic evaluation
   392→        let evaluation_task = {
   393→            let windows = Arc::clone(&windows);
   394→            let observers = observers
   395→                .into_iter()
   396→                .map(|o| (o.name(), o))
   397→                .collect::<Vec<_>>();
   398→            let mut retrain_tx = retrain_tx.clone();
   399→
   400→            tokio::spawn(async move {
   401→                let mut ticker = time::interval(DEFAULT_EVALUATION_INTERVAL);
   402→                loop {
   403→                    ticker.tick().await;
   404→                    let windows_guard = windows.read().await;
   405→
   406→                    for entry in windows_guard.iter() {
   407→                        let model = entry.key();
   408→                        let window = entry.value();
   409→
   410→                        if window.len() < 100 {
   411→                            // Not enough data yet
   412→                            continue;
   413→                        }
   414→
   415→                        let mut actions = Vec::with_capacity(observers.len());
   416→                        for (_, obs) in &observers {
   417→                            let a = obs.on_update(model, window);
   418→                            actions.push(a);
   419→                        }
   420→
   421→                        // Evaluate strategy
   422→                        if let Some(job) =
   423→                            strategy.evaluate(model, &actions, window).await
   424→                        {
   425→                            match retrain_tx.send(job.clone()) {
   426→                                Ok(_) => {
   427→                                    info!("Enqueued retrain job for model {}", model);
   428→                                    counter!("retrain_jobs_enqueued", 1, "model" => model);
   429→                                }
   430→                                Err(e) => {
   431→                                    error!("Failed to enqueue retrain job: {}", e);
   432→                                }
   433→                            }
   434→                        }
   435→                    }
   436→                }
   437→            })
   438→        };
   439→
   440→        Self {
   441→            metric_sink: MetricSink { tx: metric_tx },
   442→            retrain_job_stream: RetrainJobStream {
   443→                rx: retrain_tx.subscribe(),
   444→            },
   445→            tasks: vec![metric_task, evaluation_task],
   446→        }
   447→    }
   448→
   449→    pub fn sink(&self) -> MetricSink {
   450→        self.metric_sink.clone()
   451→    }
   452→
   453→    pub fn retrain_jobs(&self) -> RetrainJobStream {
   454→        self.retrain_job_stream.clone()
   455→    }
   456→
   457→    /// Gracefully stop tasks (await on JoinHandles)
   458→    pub async fn shutdown(self) {
   459→        for handle in self.tasks {
