    98→/// Thread-safe, in-memory implementation of a model registry.
    99→///
   100→/// In production this would be backed by a SQL/NoSQL database with audit
   101→/// logging. All writes are versioned and immutable.
   102→#[derive(Debug, Default, Clone)]
   103→pub struct ModelRegistry {
   104→    inner: Arc<RwLock<HashMap<ModelId, Vec<ModelVersion>>>>,
   105→}
   106→
   107→impl ModelRegistry {
   108→    /// Registers a new model version and returns the assigned version number.
   109→    pub fn register(
   110→        &self,
   111→        id: &ModelId,
   112→        hyper_params: HyperParams,
   113→        metrics: Metrics,
   114→    ) -> Result<u64, ModelOpsError> {
   115→        let mut guard = self
   116→            .inner
   117→            .write()
   118→            .map_err(|e| ModelOpsError::Registry(e.to_string()))?;
   119→
   120→        let versions = guard.entry(id.clone()).or_default();
   121→        let version_num = versions
   122→            .last()
   123→            .map(|v| v.version + 1)
   124→            .unwrap_or(1);
   125→
   126→        versions.push(ModelVersion {
   127→            version: version_num,
   128→            trained_at: SystemTime::now(),
   129→            hyper_params,
   130→            metrics,
   131→        });
   132→
   133→        info!("Registered model `{id}` version {version_num}");
   134→        Ok(version_num)
   135→    }
   136→
   137→    /// Returns the latest model version.
   138→    pub fn latest(&self, id: &ModelId) -> Result<ModelVersion, ModelOpsError> {
   139→        let guard = self
   140→            .inner
   141→            .read()
   142→            .map_err(|e| ModelOpsError::Registry(e.to_string()))?;
   143→
   144→        guard
   145→            .get(id)
   146→            .and_then(|v| v.last().cloned())
   147→            .ok_or_else(|| ModelOpsError::ModelNotFound(id.clone()))
   148→    }
   149→}
