   212→/// A random search tuner.
   213→pub struct RandomSearchTuner {
   214→    trials: usize,
   215→    rng: ThreadRng,
   216→}
   217→
   218→impl RandomSearchTuner {
   219→    pub fn new(trials: usize) -> Self {
