   278→//
   279→// Observer Pattern: Metrics Events & Subscriptions
   280→// -----------------------------------------------
   281→
   282→/// A metrics event emitted by the serving layer.
   283→#[derive(Debug, Clone)]
   284→pub struct MetricsEvent {
   285→    pub model_id: ModelId,
   286→    pub metrics: Metrics,
   287→}
   288→
   289→/// Observer trait used by any consumer interested in metrics events.
   290→#[async_trait]
   291→pub trait Observer: Send + Sync {
   292→    async fn update(&self, event: MetricsEvent);
   293→}
   294→
   295→/// Subject trait implemented by event producers.
   296→#[async_trait]
   297→pub trait Subject {
   298→    async fn add_observer(&self, observer: Arc<dyn Observer>);
   299→    async fn notify(&self, event: MetricsEvent);
   300→}
   301→
   302→/// Model monitor aggregates runtime metrics and notifies observers when
   303→/// degradation is detected.
   304→#[derive(Default)]
   305→pub struct ModelMonitor {
   306→    observers: Arc<RwLock<Vec<Arc<dyn Observer>>>>,
   307→}
   308→
   309→#[async_trait]
   310→impl Subject for ModelMonitor {
   311→    async fn add_observer(&self, observer: Arc<dyn Observer>) {
   312→        let mut guard = self
   313→            .observers
   314→            .write()
   315→            .expect("poisoned lock in ModelMonitor");
   316→        guard.push(observer);
   317→    }
   318→
   319→    async fn notify(&self, event: MetricsEvent) {
   320→        debug!("Notifying {} observers", self.observers.read().unwrap().len());
   321→        for obs in self.observers.read().unwrap().iter() {
   322→            obs.update(event.clone()).await;
   323→        }
   324→    }
   325→}
