   331→/// Retrains a model when metrics fall below a dynamic threshold.
   332→pub struct AutoRetrainer {
   333→    registry: ModelRegistry,
   334→    tuner: Arc<dyn HyperParamTuner>,
   335→    degradation_threshold: f64,
   336→}
   337→
   338→impl AutoRetrainer {
   339→    pub fn new(
   340→        registry: ModelRegistry,
   341→        tuner: Arc<dyn HyperParamTuner>,
   342→        degradation_threshold: f64,
   343→    ) -> Self {
   344→        Self {
   345→            registry,
   346→            tuner,
   347→            degradation_threshold,
   348→        }
   349→    }
   350→
   351→    /// Actual training routine.  In production this would call into a training
   352→    /// service, ship GPU jobs, etc.
   353→    async fn train_model(
   354→        &self,
   355→        model_id: &ModelId,
   356→        hyper_params: HyperParams,
   357→        data: DataBatch,
   358→    ) -> Result<Metrics, ModelOpsError> {
   359→        info!("Training model `{model_id}` with params {:?}", hyper_params);
   360→        // Fake training latency
   361→        sleep(Duration::from_millis(500)).await;
   362→
   363→        // Return fake metrics inversely proportional to learning rate
   364→        let val_accuracy = 0.85
   365→            + 0.1 * (1e-2 - hyper_params["learning_rate"]).clamp(0.0, 1e-2) / 1e-2;
   366→
   367→        Ok(HashMap::from([("val_accuracy".into(), val_accuracy)]))
   368→    }
   369→}
   370→
   371→#[async_trait]
   372→impl Observer for AutoRetrainer {
   373→    async fn update(&self, event: MetricsEvent) {
   374→        let acc = event.metrics.get("val_accuracy").cloned().unwrap_or(1.0);
   375→        if acc >= self.degradation_threshold {
   376→            debug!(
   377→                "Model `{}` accuracy {:.3} above threshold {:.3}, no action.",
   378→                event.model_id, acc, self.degradation_threshold
