    39→/// The VisuTility Orchestrator uses `tracing` internally, therefore having a
    40→/// subscriber in place allows both library code and our test code to emit
    41→/// diagnostics without interfering with each other.
    42→///
    43→/// We lazily initialise the subscriber on the first invocation to prevent
    44→/// double-registration panics when multiple tests are run in parallel.
    45→fn init_tracing() {
    46→    static ONCE: std::sync::Once = std::sync::Once::new();
    47→    ONCE.call_once(|| {
    48→        telemetry::configure_subscriber(Level::INFO).expect("Failed to init telemetry");
    49→    });
