    52→/// A convenience macro that wraps an async expression in a [`tokio::time::timeout`] with a
    53→/// reasonable default, turning panics into proper `anyhow::Error`s.
    54→///
    55→/// This is particularly handy in flaky CI environments where a stalled future
    56→/// would otherwise hang the entire test run.
    57→macro_rules! within {
    58→    ($duration:expr, $expr:expr) => {
    59→        timeout($duration, $expr)
    60→            .await
    61→            .with_context(|| format!("timeout after {:?}", $duration))?
    62→    };
