/// Low-level metric client for experiment tracking.
///
/// This struct is crate-private and should only be accessed through the
/// `ExperimentTracker` trait abstraction in the `experiment_tracker` module.
/// It provides direct integration with the underlying metrics infrastructure.
pub(crate) struct RawMetricClient {
    endpoint: String,
}

impl RawMetricClient {
    /// Create a new metric client pointing to the specified endpoint.
    pub(crate) fn new(endpoint: impl Into<String>) -> Self {
        Self {
            endpoint: endpoint.into(),
        }
    }

    /// Log a scalar metric value at a given training step.
    pub(crate) fn log_scalar(&self, metric_name: &str, value: f64, step: u64) {
        info!(
            endpoint = %self.endpoint,
            metric = %metric_name,
            value = %value,
            step = %step,
            "RawMetricClient: logged scalar"
        );
    }

    /// Log a hyperparameter configuration.
    pub(crate) fn log_hyperparameter(&self, param_name: &str, value: &str) {
        info!(
            endpoint = %self.endpoint,
            param = %param_name,
            value = %value,
            "RawMetricClient: logged hyperparameter"
        );
    }

    /// Upload a model artifact to the tracking server.
    pub(crate) fn upload_model_artifact(
        &self,
        local_path: &Path,
        remote_name: &str,
    ) -> Result<(), std::io::Error> {
        info!(
            endpoint = %self.endpoint,
            local_path = %local_path.display(),
            remote_name = %remote_name,
            "RawMetricClient: uploaded model artifact"
        );
        // In a real implementation, this would perform actual file upload
        Ok(())
    }
}

