//! Experiment Tracking Abstraction Layer
//! =====================================
//!
//! This module provides a trait-based abstraction for experiment tracking,
//! decoupling the core ML training and hyperparameter tuning logic from
//! concrete tracking implementations.
//!
//! # Design Rationale
//!
//! The `ExperimentTracker` trait allows for:
//! - Easy swapping of tracking backends (MLflow, W&B, local files, etc.)
//! - Mock implementations for testing without I/O
//! - Clean separation of concerns
//!
//! # Usage
//!
//! Functions that need to log metrics should accept a generic parameter
//! bounded by `ExperimentTracker`:
//!
//! ```rust
//! fn train_model<T: ExperimentTracker>(tracker: &T, ...) {
//!     tracker.log_scalar("loss", 0.5, 1);
//!     tracker.log_hyperparameter("learning_rate", "0.001");
//! }
//! ```

use std::path::Path;

use crate::RawMetricClient;

/// Trait abstracting experiment tracking operations.
///
/// Implementors of this trait can log metrics, hyperparameters, and artifacts
/// to various backends (local files, MLflow, cloud services, etc.).
pub trait ExperimentTracker: Send + Sync {
    /// Log a scalar metric value at a given training step.
    ///
    /// # Arguments
    /// * `metric_name` - Name of the metric (e.g., "loss", "accuracy")
    /// * `value` - The scalar value to log
    /// * `step` - The training step or epoch number
    fn log_scalar(&self, metric_name: &str, value: f64, step: u64);

    /// Log a hyperparameter configuration.
    ///
    /// # Arguments
    /// * `param_name` - Name of the hyperparameter (e.g., "learning_rate")
    /// * `value` - String representation of the hyperparameter value
    fn log_hyperparameter(&self, param_name: &str, value: &str);

    /// Upload a model artifact to the tracking server.
    ///
    /// # Arguments
    /// * `local_path` - Path to the local file to upload
    /// * `remote_name` - Name to use for the artifact in the tracking system
    ///
    /// # Returns
    /// * `Ok(())` on successful upload
    /// * `Err(std::io::Error)` if the upload fails
    fn upload_model_artifact(&self, local_path: &Path, remote_name: &str) -> Result<(), std::io::Error>;
}

/// Default implementation of `ExperimentTracker` that wraps `RawMetricClient`.
///
/// This struct provides a production-ready implementation that delegates
/// all tracking operations to the underlying `RawMetricClient`.
pub struct DefaultTracker {
    client: RawMetricClient,
}

impl DefaultTracker {
    /// Create a new `DefaultTracker` with the specified tracking endpoint.
    ///
    /// # Arguments
    /// * `endpoint` - The URL or connection string for the tracking server
    pub fn new(endpoint: impl Into<String>) -> Self {
        Self {
            client: RawMetricClient::new(endpoint),
        }
    }
}

impl ExperimentTracker for DefaultTracker {
    fn log_scalar(&self, metric_name: &str, value: f64, step: u64) {
        self.client.log_scalar(metric_name, value, step);
    }

    fn log_hyperparameter(&self, param_name: &str, value: &str) {
        self.client.log_hyperparameter(param_name, value);
    }

    fn upload_model_artifact(&self, local_path: &Path, remote_name: &str) -> Result<(), std::io::Error> {
        self.client.upload_model_artifact(local_path, remote_name)
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::cell::RefCell;
    use std::path::PathBuf;

    /// Mock tracker for testing that records all operations.
    struct MockTracker {
        scalars: RefCell<Vec<(String, f64, u64)>>,
        hyperparams: RefCell<Vec<(String, String)>>,
        artifacts: RefCell<Vec<(PathBuf, String)>>,
    }

    impl MockTracker {
        fn new() -> Self {
            Self {
                scalars: RefCell::new(Vec::new()),
                hyperparams: RefCell::new(Vec::new()),
                artifacts: RefCell::new(Vec::new()),
            }
        }

        fn scalar_count(&self) -> usize {
            self.scalars.borrow().len()
        }

        fn hyperparam_count(&self) -> usize {
            self.hyperparams.borrow().len()
        }

        fn artifact_count(&self) -> usize {
            self.artifacts.borrow().len()
        }
    }

    impl ExperimentTracker for MockTracker {
        fn log_scalar(&self, metric_name: &str, value: f64, step: u64) {
            self.scalars.borrow_mut().push((metric_name.to_string(), value, step));
        }

        fn log_hyperparameter(&self, param_name: &str, value: &str) {
