/// Log hyperparameters to an experiment tracker.
///
/// This function accepts any type that implements the `ExperimentTracker` trait,
/// allowing for easy testing with mocks and swapping of tracking backends.
pub fn log_hyperparams<T: ExperimentTracker>(
    tracker: &T,
    params: &HyperParams,
) {
    for (name, value) in params {
        tracker.log_hyperparameter(name, &value.to_string());
    }
}

/// Log training metrics to an experiment tracker.
///
/// Records each metric in the provided map at the specified step.
pub fn log_training_metrics<T: ExperimentTracker>(
    tracker: &T,
    metrics: &Metrics,
    step: u64,
) {
    for (name, value) in metrics {
        tracker.log_scalar(name, *value, step);
    }
}

