/// A simple grid search tuner.
pub struct GridSearchTuner {
    learning_rates: Vec<f64>,
    num_layers: Vec<f64>,
}

impl GridSearchTuner {
    pub fn new() -> Self {
        Self {
            learning_rates: vec![1e-4, 1e-3, 1e-2],
            num_layers: vec![2.0, 3.0, 4.0],
        }
    }
