/// This function coordinates hyperparameter tuning, model training, and
/// result logging through the provided `ExperimentTracker`.
pub async fn run_training_pipeline<T: ExperimentTracker>(
    tracker: &T,
    tuner: Arc<dyn HyperParamTuner>,
    model_id: &ModelId,
    data: DataBatch,
    registry: &ModelRegistry,
) -> Result<u64, ModelOpsError> {
    // Step 1: Hyperparameter tuning
    let params = tuner.tune(model_id, &data).await?;
    log_hyperparams(tracker, &params);

    // Step 2: Train model (simulated)
    info!("Training model `{model_id}` with params {:?}", params);
    let val_accuracy = 0.85 + 0.1 * (1e-2 - params["learning_rate"]).clamp(0.0, 1e-2) / 1e-2;
    let metrics = HashMap::from([("val_accuracy".into(), val_accuracy)]);

    // Step 3: Log metrics
    log_training_metrics(tracker, &metrics, 1);

    // Step 4: Register model
    let version = registry.register(model_id, params, metrics)?;

    info!("Model `{model_id}` trained and registered as version {version}");
    Ok(version)
}

#[async_trait]
impl<T: ExperimentTracker + Send + Sync + 'static> Observer for AutoRetrainer<T> {
    async fn update(&self, event: MetricsEvent) {
        let acc = event.metrics.get("val_accuracy").cloned().unwrap_or(1.0);
        if acc >= self.degradation_threshold {
            debug!(
                "Model `{}` accuracy {:.3} above threshold {:.3}, no action.",
                event.model_id, acc, self.degradation_threshold
            );
            return;
        }

        warn!(
            "Model `{}` accuracy {:.3} below threshold {:.3}, initiating retraining.",
            event.model_id, acc, self.degradation_threshold
        );

        let registry_clone = self.registry.clone();
        let tuner_clone = self.tuner.clone();
        let model_id = event.model_id.clone();
        let tracker_clone = Arc::clone(&self.tracker);

        // Fire-and-forget background task
        if let Err(e) = task::spawn(async move {
            // Step 1: Pull fresh data — here we fake it
            let data = DataBatch { num_samples: 10_000 };

            // Step 2: Hyper-parameter tuning
            let tuned_params = tuner_clone.tune(&model_id, &data).await?;

            // Log hyperparameters using the tracker
            log_hyperparams(tracker_clone.as_ref(), &tuned_params);

            // Step 3: Train
            let new_metrics = train_model_static(
                &model_id,
                tuned_params.clone(),
                data,
                tracker_clone.as_ref(),
            ).await?;

            // Step 4: Register new version
            registry_clone
                .register(&model_id, tuned_params, new_metrics)
                .map(|v| info!("Model `{}` retrained, new version {}", model_id, v))
        })
        .await
        {
            error!("Failed to spawn retraining task: {e}");
        }
    }
}

