// ----------------------------------------------------------------------------
// Boiler-plate test helpers
// ----------------------------------------------------------------------------

/// Initialize tracing + telemetry once for the whole test-suite.
///
/// The VisuTility Orchestrator uses `tracing` internally, therefore having a
/// subscriber in place allows both library code and our test code to emit
/// diagnostics without interfering with each other.
///
/// We lazily initialise the subscriber on the first invocation to prevent
/// double-registration panics when multiple tests are run in parallel.
fn init_tracing() {
    static ONCE: std::sync::Once = std::sync::Once::new();
    ONCE.call_once(|| {
        telemetry::configure_subscriber(Level::INFO).expect("Failed to init telemetry");
    });
}

/// A convenience macro that wraps an async expression in a [`tokio::time::timeout`] with a
/// reasonable default, turning panics into proper `anyhow::Error`s.
///
/// This is particularly handy in flaky CI environments where a stalled future
/// would otherwise hang the entire test run.
macro_rules! within {
    ($duration:expr, $expr:expr) => {
        timeout($duration, $expr)
            .await
            .with_context(|| format!("timeout after {:?}", $duration))?
    };
}

// ----------------------------------------------------------------------------
// MockTracker Implementation
// ----------------------------------------------------------------------------

/// Mock experiment tracker for testing that records all operations without
/// performing any I/O.
///
/// This struct uses `RefCell` for interior mutability, allowing it to record
/// method calls while maintaining the trait's `&self` signature requirement.
/// It provides methods to query the recorded operations for test assertions.
pub struct MockTracker {
    /// Records (metric_name, value, step) tuples from log_scalar calls
    scalars: RefCell<Vec<(String, f64, u64)>>,
    /// Records (param_name, value) tuples from log_hyperparameter calls
    hyperparams: RefCell<Vec<(String, String)>>,
    /// Records (local_path, remote_name) tuples from upload_model_artifact calls
    artifacts: RefCell<Vec<(PathBuf, String)>>,
}

impl MockTracker {
    /// Create a new MockTracker with empty internal state.
    pub fn new() -> Self {
        Self {
            scalars: RefCell::new(Vec::new()),
            hyperparams: RefCell::new(Vec::new()),
            artifacts: RefCell::new(Vec::new()),
        }
    }

    /// Returns the number of scalar metrics logged.
    pub fn scalar_count(&self) -> usize {
        self.scalars.borrow().len()
    }

    /// Returns the number of hyperparameters logged.
    pub fn hyperparam_count(&self) -> usize {
        self.hyperparams.borrow().len()
    }

    /// Returns the number of artifacts uploaded.
    pub fn artifact_count(&self) -> usize {
        self.artifacts.borrow().len()
    }

    /// Returns a copy of all logged scalar metrics.
    pub fn get_scalars(&self) -> Vec<(String, f64, u64)> {
        self.scalars.borrow().clone()
    }

    /// Returns a copy of all logged hyperparameters.
    pub fn get_hyperparams(&self) -> Vec<(String, String)> {
        self.hyperparams.borrow().clone()
    }

    /// Returns a copy of all uploaded artifacts.
    pub fn get_artifacts(&self) -> Vec<(PathBuf, String)> {
        self.artifacts.borrow().clone()
    }

    /// Check if a specific metric was logged.
    pub fn has_metric(&self, name: &str) -> bool {
        self.scalars.borrow().iter().any(|(n, _, _)| n == name)
    }

    /// Check if a specific hyperparameter was logged.
    pub fn has_hyperparam(&self, name: &str) -> bool {
        self.hyperparams.borrow().iter().any(|(n, _)| n == name)
    }

    /// Clear all recorded data for reuse in multiple test scenarios.
    pub fn clear(&self) {
        self.scalars.borrow_mut().clear();
        self.hyperparams.borrow_mut().clear();
        self.artifacts.borrow_mut().clear();
    }
}

impl Default for MockTracker {
    fn default() -> Self {
        Self::new()
    }
}

impl ExperimentTracker for MockTracker {
    fn log_scalar(&self, metric_name: &str, value: f64, step: u64) {
        self.scalars.borrow_mut().push((
            metric_name.to_string(),
            value,
            step,
        ));
    }

    fn log_hyperparameter(&self, param_name: &str, value: &str) {
        self.hyperparams.borrow_mut().push((
            param_name.to_string(),
            value.to_string(),
        ));
    }

    fn upload_model_artifact(
        &self,
        local_path: &Path,
        remote_name: &str,
    ) -> Result<(), std::io::Error> {
        self.artifacts.borrow_mut().push((
            local_path.to_path_buf(),
            remote_name.to_string(),
        ));
        Ok(())
    }
}

